/**
 * Design Tokens for Staff App
 * Centralized design system values for consistent styling
 */

export const SPACING = {
  xs: 4,
  sm: 8,
  md: 16,
  lg: 24,
  xl: 32,
  xxl: 48,
} as const;

export const BORDER_RADIUS = {
  sm: 8,
  md: 12,
  lg: 16,
  xl: 20,
  full: 9999,
} as const;

export const TYPOGRAPHY = {
  h1: 32,
  h2: 24,
  h3: 20,
  h4: 18,
  body: 16,
  bodySmall: 14,
  caption: 12,
} as const;

export const ICON_SIZE = {
  sm: 16,
  md: 20,
  lg: 24,
  xl: 32,
} as const;

export type Spacing = typeof SPACING[keyof typeof SPACING];
export type BorderRadius = typeof BORDER_RADIUS[keyof typeof BORDER_RADIUS];
export type Typography = typeof TYPOGRAPHY[keyof typeof TYPOGRAPHY];
export type IconSize = typeof ICON_SIZE[keyof typeof ICON_SIZE];

