    33→  const { colors } = useTheme();
    34→  const { profile, syncStatus, isLoading, refetch } = useStaffProfile();
    35→  const [isSaving, setIsSaving] = useState(false);
    36→  const [showBloodGroupPicker, setShowBloodGroupPicker] = useState(false);
    37→  const [showMaritalStatusPicker, setShowMaritalStatusPicker] = useState(false);
    38→
    39→  // Form setup with validation
    40→  const {
    41→    control,
    42→    handleSubmit,
    43→    setValue,
    44→    reset,
    45→    formState: { isDirty, errors, isValid, dirtyFields },
    46→  } = useForm<ProfileUpdateFormData>({
    47→    resolver: zodResolver(profileUpdateSchema),
    48→    defaultValues: {
    49→      phone: '',
    50→      email: '',
    51→      whatsappNumber: '',
    52→      bloodGroup: undefined,
    53→      maritalStatus: undefined,
    54→      address: '',
    55→      emergencyContacts: [
    56→        {
    57→          name: '',
    58→          relationship: '',
    59→          phone: '',
    60→        },
    61→      ],
    62→    },
    63→    mode: 'all', // Validate on blur and change
    64→  });
    65→
    66→  // Emergency contacts array management
    67→  const { fields, append, remove } = useFieldArray({
    68→    control,
    69→    name: 'emergencyContacts',
    70→  });
    71→
    72→  // Reset form when profile loads
    73→  useEffect(() => {
    74→    if (profile) {
    75→      console.log('Loading profile data:', profile);
    76→      console.log('Emergency contacts:', profile.emergencyContacts);
    77→
    78→      reset({
    79→        phone: profile.phone || '',
    80→        email: profile.email || '',
    81→        whatsappNumber: profile.whatsappNumber || '',
    82→        bloodGroup: profile.bloodGroup,
    83→        maritalStatus: profile.maritalStatus,
    84→        address: profile.address || '',
    85→        emergencyContacts: profile.emergencyContacts && profile.emergencyContacts.length > 0
    86→          ? profile.emergencyContacts.map((contact) => ({
    87→              name: contact.name || '',
    88→              relationship: contact.relationship || '',
    89→              phone: contact.phone || '',
    90→            }))
    91→          : [{ name: '', relationship: '', phone: '' }],
    92→      });
    93→    }
    94→  }, [profile, reset]);
    95→
    96→  // Handle form submission
    97→  const onSubmit = async (data: ProfileUpdateFormData) => {
    98→    console.log('Form submitted with data:', data);
    99→    console.log('Form isDirty:', isDirty);
   100→    console.log('Form isValid:', isValid);
   101→    console.log('Form errors:', errors);
   102→
   103→    if (!user?.id) {
   104→      Alert.alert('Error', 'User not authenticated');
   105→      return;
   106→    }
   107→
   108→    try {
   109→      setIsSaving(true);
   110→
   111→      await api.updateStaffProfile(user.id, data);
   112→
   113→      Alert.alert(
   114→        'Success',
   115→        'Profile updated successfully',
   116→        [
   117→          {
   118→            text: 'OK',
   119→            onPress: () => {
   120→              refetch(); // Refresh profile data
   121→              router.back();
   122→            },
   123→          },
   124→        ],
   125→        { cancelable: false }
