   129→      Alert.alert(
   130→        'Error',
   131→        error.message || 'Failed to update profile. Please try again.'
   132→      );
   133→    } finally {
   134→      setIsSaving(false);
   135→    }
   136→  };
   137→
   138→  // Handle form submission with validation error display
   139→  const handleSavePress = async () => {
   140→    console.log('Save button pressed');
   141→    console.log('isDirty:', isDirty);
   142→    console.log('isValid:', isValid);
   143→    console.log('errors:', errors);
   144→    console.log('dirtyFields:', dirtyFields);
