   172→          errorMessages.push(`${field}: ${error.message}`);
   173→        }
   174→      });
   175→
   176→      // Check emergency contact individual fields
   177→      if (Array.isArray(errors.emergencyContacts)) {
   178→        errors.emergencyContacts.forEach((contactError: any, index: number) => {
   179→          if (contactError?.name?.message) {
   180→            errorMessages.push(`Contact ${index + 1} - Name: ${contactError.name.message}`);
   181→          }
   182→          if (contactError?.relationship?.message) {
   183→            errorMessages.push(`Contact ${index + 1} - Relationship: ${contactError.relationship.message}`);
   184→          }
   185→          if (contactError?.phone?.message) {
   186→            errorMessages.push(`Contact ${index + 1} - Phone: ${contactError.phone.message}`);
   187→          }
   188→        });
   189→      }
   190→
   191→      console.log('Error messages:', errorMessages);
   192→
   193→      if (errorMessages.length > 0) {
   194→        Alert.alert(
   195→          'Validation Errors',
   196→          'Please fix the following errors:\n\n' + errorMessages.join('\n')
   197→        );
   198→      } else {
   199→        Alert.alert(
   200→          'Validation Error',
   201→          'Please make sure all required fields are filled correctly:\n\n• Phone number (10 digits)\n• At least one complete emergency contact (name, relationship, phone)'
   202→        );
   203→      }
   204→      return;
   205→    }
   206→
   207→    // Form is valid, submit it
   208→    handleSubmit((data) => {
   209→      console.log('Validation passed, submitting...');
   210→      onSubmit(data);
