   212→  };
   213→
   214→  // Add emergency contact
   215→  const handleAddContact = () => {
   216→    if (fields.length < 5) {
   217→      append({ name: '', relationship: '', phone: '' });
   218→    } else {
   219→      Alert.alert('Maximum Limit', 'You can only add up to 5 emergency contacts');
   220→    }
   221→  };
   222→
   223→  // Remove emergency contact
   224→  const handleRemoveContact = (index: number) => {
   225→    if (fields.length > 1) {
   226→      remove(index);
   227→    } else {
   228→      Alert.alert('Required', 'At least one emergency contact is required');
   229→    }
   230→  };
   231→
   232→  // Show loading state
