import React, { useEffect, useState, useCallback } from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  TextInput,
  Alert,
  ActivityIndicator,
  Modal,
  Platform,
} from 'react-native';
import DateTimePicker, { DateTimePickerEvent } from '@react-native-community/datetimepicker';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { useLocalSearchParams, Stack } from 'expo-router';
import api from '../services/api';
import { format } from 'date-fns';
import { Ionicons } from '@expo/vector-icons';

export default function HomeworkScreen() {
  const { user } = useAuth();
  const { colors } = useTheme();
  const { action } = useLocalSearchParams();
  const [homeworkList, setHomeworkList] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreateModal, setShowCreateModal] = useState(false);
  const [newHomework, setNewHomework] = useState({
    title: '',
    description: '',
    subject: '',
    dueDate: new Date(),
  });
  const [showDatePicker, setShowDatePicker] = useState(false);

  useEffect(() => {
    if (action === 'create') {
      setShowCreateModal(true);
    }
  }, [action]);

  const loadHomework = useCallback(async () => {
    if (!user?.id) return;
    try {
      const data = await api.getHomework(user.id);
      setHomeworkList(data);
    } catch (error) {
      console.error('Error loading homework:', error);
      Alert.alert('Error', 'Failed to load homework. Please try again.');
    } finally {
      setLoading(false);
    }
  }, [user?.id]);

  useEffect(() => {
    loadHomework();
  }, [loadHomework]);

  const createHomework = useCallback(async () => {
    if (!user?.id || !newHomework.title || !newHomework.description || !newHomework.subject) {
      Alert.alert('Error', 'Please fill all required fields');
      return;
    }

    // Check if user has classes assigned
    if (!user.classes || user.classes.length === 0) {
      Alert.alert('Error', 'You are not assigned to any class. Please contact the administrator.');
      return;
    }

    const classId = user.classes[0]?.id;
    if (!classId) {
      Alert.alert('Error', 'Invalid class assignment. Please contact the administrator.');
      return;
    }

    try {
      await api.createHomework({
        title: newHomework.title,
        description: newHomework.description,
        subject: newHomework.subject,
        dueDate: format(newHomework.dueDate, 'yyyy-MM-dd'),
        teacherId: user.id,
        classId: classId,
      });
      Alert.alert('Success', 'Homework created successfully');
      setShowCreateModal(false);
      setNewHomework({ title: '', description: '', subject: '', dueDate: new Date() });
      loadHomework();
    } catch (error: any) {
      console.error('Error creating homework:', error);
      Alert.alert('Error', error.message || 'Failed to create homework');
    }
  }, [user, newHomework, loadHomework]);

  if (loading) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.backgroundGray }}>
        <ActivityIndicator size="large" color={colors.primary} />
      </View>
    );
  }

  return (
    <>
      <Stack.Screen options={{ title: 'Homework', headerShown: true }} />
      <View style={{ flex: 1, backgroundColor: colors.backgroundGray }}>
        <ScrollView style={{ flex: 1, padding: 16 }}>
          {homeworkList.length > 0 ? (
            homeworkList.map((hw) => (
              <View key={hw._id} style={{ padding: 16, marginBottom: 12, backgroundColor: colors.card, borderRadius: 12, shadowColor: '#000', shadowOffset: { width: 0, height: 2 }, shadowOpacity: 0.1, shadowRadius: 4, elevation: 3 }}>
                <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
                  <Text style={{ fontSize: 18, fontWeight: 'bold', color: colors.text, flex: 1 }}>{hw.title}</Text>
                  <View style={[{ paddingHorizontal: 12, paddingVertical: 4, borderRadius: 12 }, hw.status === 'active' ? { backgroundColor: colors.success + '20' } : { backgroundColor: colors.error + '20' }]}>
                    <Text style={{ fontSize: 12, fontWeight: '600', color: hw.status === 'active' ? colors.success : colors.error }}>{hw.status}</Text>
                  </View>
                </View>
                <Text style={{ fontSize: 14, color: colors.primary, marginBottom: 4 }}>{hw.subject}</Text>
                <Text style={{ fontSize: 14, color: colors.text, marginBottom: 8 }}>{hw.description}</Text>
                {hw.classId && (
                  <Text style={{ fontSize: 12, color: colors.textSecondary }}>
                    Class {hw.classId.name} {hw.classId.section}
                  </Text>
                )}
                {hw.dueDate && (
                  <Text style={{ fontSize: 12, color: colors.textSecondary, marginTop: 4 }}>
                    Due: {format(new Date(hw.dueDate), 'MMM d, yyyy')}
                  </Text>
                )}
                {hw.submissions && hw.submissions.length > 0 && (
                  <Text style={{ fontSize: 12, color: colors.primary, marginTop: 8, fontWeight: '600' }}>
                    {hw.submissions.length} submissions
                  </Text>
                )}
              </View>
            ))
          ) : (
            <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
              <Text style={{ fontSize: 16, color: colors.textSecondary }}>No homework assigned yet</Text>
            </View>
          )}
        </ScrollView>

        <TouchableOpacity
          style={{ position: 'absolute', right: 20, bottom: 20, width: 56, height: 56, borderRadius: 28, backgroundColor: colors.primary, justifyContent: 'center', alignItems: 'center', shadowColor: '#000', shadowOffset: { width: 0, height: 4 }, shadowOpacity: 0.3, shadowRadius: 4, elevation: 8 }}
          onPress={() => setShowCreateModal(true)}
        >
          <Text style={{ fontSize: 32, color: colors.white, fontWeight: 'bold' }}>+</Text>
        </TouchableOpacity>

        <CreateHomeworkModal
          visible={showCreateModal}
          homework={newHomework}
          setHomework={setNewHomework}
          onCreate={createHomework}
          onClose={() => setShowCreateModal(false)}
        />
      </View>
    </>
  );
}

interface CreateHomeworkModalProps {
  visible: boolean;
  homework: {
    title: string;
    description: string;
    subject: string;
    dueDate: Date;
  };
  setHomework: (homework: any) => void;
  onCreate: () => void;
  onClose: () => void;
}

function CreateHomeworkModal({
  visible,
  homework,
  setHomework,
  onCreate,
  onClose,
}: CreateHomeworkModalProps) {
  const { colors } = useTheme();
  const [showDatePicker, setShowDatePicker] = useState(false);

  const onDateChange = (event: DateTimePickerEvent, selectedDate?: Date) => {
    setShowDatePicker(Platform.OS === 'ios');
    if (selectedDate) {
      setHomework({ ...homework, dueDate: selectedDate });
    }
  };

  return (
    <Modal visible={visible} animationType="slide" transparent>
      <View style={{ flex: 1, justifyContent: 'flex-end', backgroundColor: 'rgba(0, 0, 0, 0.5)' }}>
        <View style={{ padding: 24, backgroundColor: colors.card, borderTopLeftRadius: 24, borderTopRightRadius: 24, maxHeight: '90%' }}>
          <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
            <Text style={{ fontSize: 24, fontWeight: 'bold', color: colors.text }}>Create Homework</Text>
            <TouchableOpacity onPress={onClose}>
              <Ionicons name="close" size={24} color={colors.textSecondary} />
            </TouchableOpacity>
          </View>

          <ScrollView showsVerticalScrollIndicator={false}>
            <Text style={{ fontSize: 14, fontWeight: '600', color: colors.textSecondary, marginBottom: 8 }}>Title *</Text>
            <TextInput
              style={{ borderWidth: 1, borderColor: colors.border, borderRadius: 12, padding: 14, fontSize: 16, color: colors.text, backgroundColor: colors.inputBackground, marginBottom: 16 }}
              placeholder="Enter homework title"
              placeholderTextColor={colors.textSecondary}
              value={homework.title}
              onChangeText={(text) => setHomework({ ...homework, title: text })}
            />

            <Text style={{ fontSize: 14, fontWeight: '600', color: colors.textSecondary, marginBottom: 8 }}>Description *</Text>
            <TextInput
              style={{ borderWidth: 1, borderColor: colors.border, borderRadius: 12, padding: 14, fontSize: 16, color: colors.text, backgroundColor: colors.inputBackground, marginBottom: 16, minHeight: 100, textAlignVertical: 'top' }}
              placeholder="Enter homework description"
              placeholderTextColor={colors.textSecondary}
              value={homework.description}
              onChangeText={(text) => setHomework({ ...homework, description: text })}
              multiline
              numberOfLines={4}
            />

            <Text style={{ fontSize: 14, fontWeight: '600', color: colors.textSecondary, marginBottom: 8 }}>Subject *</Text>
            <TextInput
              style={{ borderWidth: 1, borderColor: colors.border, borderRadius: 12, padding: 14, fontSize: 16, color: colors.text, backgroundColor: colors.inputBackground, marginBottom: 16 }}
              placeholder="Enter subject"
              placeholderTextColor={colors.textSecondary}
              value={homework.subject}
              onChangeText={(text) => setHomework({ ...homework, subject: text })}
            />

            <Text style={{ fontSize: 14, fontWeight: '600', color: colors.textSecondary, marginBottom: 8 }}>Due Date</Text>
            <TouchableOpacity
              style={{ flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', borderWidth: 1, borderColor: colors.border, borderRadius: 12, padding: 14, backgroundColor: colors.inputBackground, marginBottom: 24 }}
              onPress={() => setShowDatePicker(true)}
            >
              <Text style={{ fontSize: 16, color: colors.text }}>
                {format(homework.dueDate, 'MMMM d, yyyy')}
              </Text>
              <Ionicons name="calendar-outline" size={20} color={colors.primary} />
            </TouchableOpacity>

            {showDatePicker && (
              <DateTimePicker
                value={homework.dueDate}
                mode="date"
                display={Platform.OS === 'ios' ? 'spinner' : 'default'}
                onChange={onDateChange}
                minimumDate={new Date()}
              />
            )}

            <View style={{ flexDirection: 'row', gap: 12, marginTop: 8, paddingBottom: 16 }}>
              <TouchableOpacity
                style={{ flex: 1, padding: 16, borderRadius: 12, alignItems: 'center', backgroundColor: colors.inputBackground }}
                onPress={onClose}
              >
                <Text style={{ color: colors.textSecondary, fontWeight: '600', fontSize: 16 }}>Cancel</Text>
              </TouchableOpacity>
              <TouchableOpacity
                style={{ flex: 1, padding: 16, borderRadius: 12, alignItems: 'center', backgroundColor: colors.primary }}
                onPress={onCreate}
              >
                <Text style={{ color: colors.white, fontWeight: '600', fontSize: 16 }}>Create</Text>
              </TouchableOpacity>
            </View>
          </ScrollView>
        </View>
      </View>
    </Modal>
  );
}

