            />
          ))}
          {typingUsers.size > 0 && <TypingIndicator colors={colors} />}
        </ScrollView>

        {/* Input Area */}
        <KeyboardAvoidingView
          behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
          keyboardVerticalOffset={Platform.OS === 'ios' ? 90 : 0}
        >
          <View style={[styles.inputWrapper, { backgroundColor: colors.card, borderTopColor: colors.border }]}>
            {/* Reply Indicator */}
            {replyingTo && (
              <View style={[styles.replyToContainer, { backgroundColor: colors.backgroundGray, borderBottomColor: colors.border }]}>
                <View style={styles.replyToContent}>
                  <View style={[styles.replyToBar, { backgroundColor: colors.primary }]} />
                  <View style={styles.replyToText}>
                    <Text style={[styles.replyToLabel, { color: colors.primary }]}>
                      Replying to {replyingTo.senderName}
                    </Text>
                    <Text style={[styles.replyToMessage, { color: colors.textSecondary }]} numberOfLines={1}>
                      {replyingTo.content || (replyingTo.type === 'image' ? '📷 Image' : '📎 File')}
                    </Text>
                  </View>
                </View>
                <TouchableOpacity onPress={cancelReply} style={styles.replyToCancel}>
                  <Ionicons name="close-circle" size={20} color={colors.textSecondary} />
                </TouchableOpacity>
              </View>
            )}

            {/* Edit Message Indicator */}
            {editingMessage && (
              <View style={[styles.editContainer, { backgroundColor: colors.primary + '10', borderBottomColor: colors.border }]}>
                <View style={styles.editContent}>
                  <View style={[styles.editBar, { backgroundColor: colors.primary }]} />
                  <View style={styles.editText}>
                    <Text style={[styles.editLabel, { color: colors.primary }]}>
                      Editing message
                    </Text>
                    <Text style={[styles.editMessage, { color: colors.textSecondary }]} numberOfLines={1}>
                      {editingMessage.content}
                    </Text>
                  </View>
                </View>
                <TouchableOpacity onPress={cancelEdit} style={styles.editCancel}>
                  <Ionicons name="close-circle" size={20} color={colors.textSecondary} />
                </TouchableOpacity>
              </View>
            )}

            {/* File Preview */}
            {selectedFile && (
              <View style={[styles.filePreviewContainer, { borderBottomColor: colors.border }]}>
                {selectedFile.type.startsWith('image/') ? (
                  <Image source={{ uri: selectedFile.uri }} style={styles.filePreviewImage} />
                ) : (
                  <View style={styles.filePreviewPlaceholder}>
                    <Ionicons name="document" size={32} color={colors.primary} />
                  </View>
                )}
                <View style={styles.filePreviewInfo}>
                  <Text style={[styles.filePreviewName, { color: colors.text }]} numberOfLines={1}>
                    {selectedFile.name}
                  </Text>
                  {selectedFile.size && (
                    <Text style={[styles.filePreviewSize, { color: colors.textSecondary }]}>
                      {(selectedFile.size / 1024).toFixed(2)} KB
                    </Text>
                  )}
                </View>
                {uploadingFile ? (
                  <View style={styles.uploadProgressContainer}>
                    <ActivityIndicator size="small" color={colors.primary} />
                    <Text style={[styles.uploadProgressText, { color: colors.primary }]}>{uploadProgress}%</Text>
                  </View>
                ) : (
                  <>
                    <TouchableOpacity
                      style={[styles.fileSendButton, { backgroundColor: colors.primary }]}
                      onPress={handleFileUpload}
                    >
                      <Ionicons name="send" size={20} color={colors.white} />
                    </TouchableOpacity>
                    <TouchableOpacity
                      style={[styles.fileCancelButton, { backgroundColor: colors.border }]}
                      onPress={cancelFileUpload}
                    >
                      <Ionicons name="close" size={20} color={colors.text} />
                    </TouchableOpacity>
                  </>
                )}
              </View>
            )}

            <View style={styles.inputContainer}>
              <TouchableOpacity
                style={styles.attachButton}
                onPress={() => setShowAttachmentModal(true)}
              >
                <Ionicons name="add-circle" size={28} color={colors.primary} />
              </TouchableOpacity>
              <View style={[styles.inputInner, { backgroundColor: colors.inputBackground, borderColor: colors.border }]}>
                <TextInput
                  ref={inputRef}
                  style={[styles.input, { color: colors.text }]}
                  value={editingMessage ? editText : newMessage}
                  onChangeText={editingMessage ? setEditText : handleTyping}
                  placeholder={editingMessage ? "Edit message..." : "Type a message..."}
                  placeholderTextColor={colors.textSecondary}
                  multiline
                  maxLength={1000}
                />
              </View>
              {editingMessage ? (
                <TouchableOpacity
                  style={[styles.sendButton, { backgroundColor: colors.success }, !editText.trim() && styles.sendButtonHidden]}
                  onPress={handleEditMessage}
                >
                  <Ionicons name="checkmark" size={22} color={colors.white} />
                </TouchableOpacity>
              ) : (
                <TouchableOpacity
                  style={[styles.sendButton, { backgroundColor: colors.primary }, !newMessage.trim() && styles.sendButtonHidden]}
                  onPress={sendMessage}
                  disabled={sending}
                >
                  {sending ? (
                    <ActivityIndicator size="small" color={colors.white} />
                  ) : (
                    <Ionicons name="send" size={20} color={colors.white} />
                  )}
                </TouchableOpacity>
              )}
            </View>
          </View>
        </KeyboardAvoidingView>

        {/* Attachment Options Modal */}
        <Modal
          visible={showAttachmentModal}
          transparent={true}
          animationType="slide"
          onRequestClose={() => setShowAttachmentModal(false)}
        >
          <TouchableOpacity
            style={styles.modalOverlay}
            activeOpacity={1}
            onPress={() => setShowAttachmentModal(false)}
          >
            <View style={[styles.attachmentModalContent, { backgroundColor: colors.card }]}>
              <View style={[styles.attachmentModalHeader, { borderBottomColor: colors.border }]}>
                <Text style={[styles.attachmentModalTitle, { color: colors.text }]}>Send Attachment</Text>
                <TouchableOpacity
                  style={[styles.attachmentCloseButton, { backgroundColor: colors.border }]}
                  onPress={() => setShowAttachmentModal(false)}
                >
                  <Ionicons name="close" size={24} color={colors.text} />
                </TouchableOpacity>
              </View>

              <View style={styles.attachmentOptionsContainer}>
                <TouchableOpacity
                  style={[styles.attachmentOption, { backgroundColor: colors.backgroundGray }]}
                  onPress={() => requestPermissionsAndPickImage(false)}
                >
                  <View style={[styles.attachmentOptionIcon, { backgroundColor: colors.primary + '15' }]}>
                    <Ionicons name="images" size={32} color={colors.primary} />
                  </View>
                  <Text style={[styles.attachmentOptionText, { color: colors.text }]}>Photo Library</Text>
                  <Text style={[styles.attachmentOptionSubtext, { color: colors.textSecondary }]}>Choose from gallery</Text>
                </TouchableOpacity>

                <TouchableOpacity
                  style={[styles.attachmentOption, { backgroundColor: colors.backgroundGray }]}
                  onPress={() => requestPermissionsAndPickImage(true)}
                >
                  <View style={[styles.attachmentOptionIcon, { backgroundColor: colors.primary + '15' }]}>
                    <Ionicons name="camera" size={32} color={colors.primary} />
                  </View>
                  <Text style={[styles.attachmentOptionText, { color: colors.text }]}>Camera</Text>
                  <Text style={[styles.attachmentOptionSubtext, { color: colors.textSecondary }]}>Take a photo</Text>
                </TouchableOpacity>
              </View>
            </View>
          </TouchableOpacity>
        </Modal>

        {/* Message Actions Modal */}
        <Modal
          visible={showMessageActions}
          transparent={true}
          animationType="fade"
          onRequestClose={() => setShowMessageActions(false)}
        >
          <TouchableOpacity
            style={styles.modalOverlay}
            activeOpacity={1}
            onPress={() => setShowMessageActions(false)}
          >
            <View style={styles.messageActionsContainer}>
              <View style={[styles.messageActionsContent, { backgroundColor: colors.card }]}>
                <View style={[styles.messageActionsHeader, { borderBottomColor: colors.border }]}>
                  <Text style={[styles.messageActionsTitle, { color: colors.text }]}>Message Actions</Text>
                  <TouchableOpacity
                    style={[styles.messageActionsCloseButton, { backgroundColor: colors.border }]}
                    onPress={() => setShowMessageActions(false)}
                  >
                    <Ionicons name="close" size={24} color={colors.text} />
                  </TouchableOpacity>
                </View>

                <View style={styles.messageActionsList}>
                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction('reply')}
                  >
                    <Ionicons name="arrow-undo" size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>Reply</Text>
                  </TouchableOpacity>

                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction('forward')}
                  >
                    <Ionicons name="arrow-forward" size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>Forward</Text>
                  </TouchableOpacity>

                  {String(selectedMessageForAction?.senderId) === String(user?.id) && (
                    <>
                      <TouchableOpacity
                        style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                        onPress={() => handleMessageAction('edit')}
                      >
                        <Ionicons name="create" size={24} color={colors.primary} />
                        <Text style={[styles.messageActionText, { color: colors.text }]}>Edit</Text>
                      </TouchableOpacity>

                      <TouchableOpacity
                        style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                        onPress={() => handleMessageAction('delete')}
                      >
                        <Ionicons name="trash" size={24} color={colors.error} />
                        <Text style={[styles.messageActionText, { color: colors.error }]}>Delete</Text>
                      </TouchableOpacity>
                    </>
                  )}

                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction('copy')}
                  >
                    <Ionicons name="copy" size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>Copy Text</Text>
                  </TouchableOpacity>

                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction('react')}
                  >
                    <Ionicons name="happy-outline" size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>React</Text>
                  </TouchableOpacity>

                  <TouchableOpacity
                    style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                    onPress={() => handleMessageAction(selectedMessageForAction?.pinned ? 'unpin' : 'pin')}
                  >
                    <Ionicons name={selectedMessageForAction?.pinned ? "pin" : "pin-outline"} size={24} color={colors.primary} />
                    <Text style={[styles.messageActionText, { color: colors.text }]}>
                      {selectedMessageForAction?.pinned ? 'Unpin' : 'Pin'}
                    </Text>
                  </TouchableOpacity>

                  {(selectedMessageForAction?.type === 'file' || selectedMessageForAction?.type === 'image') && (
                    <TouchableOpacity
                      style={[styles.messageActionItem, { backgroundColor: colors.backgroundGray }]}
                      onPress={() => handleMessageAction('download')}
                    >
                      <Ionicons name="download" size={24} color={colors.primary} />
                      <Text style={[styles.messageActionText, { color: colors.text }]}>Download</Text>
                    </TouchableOpacity>
                  )}
                </View>
              </View>
            </View>
          </TouchableOpacity>
        </Modal>

        {/* Emoji Picker Modal */}
        <Modal
          visible={showEmojiPicker}
          transparent={true}
          animationType="fade"
          onRequestClose={() => setShowEmojiPicker(false)}
        >
          <TouchableOpacity
            style={styles.modalOverlay}
            activeOpacity={1}
            onPress={() => {
              setShowEmojiPicker(false);
              setSelectedMessageForAction(null);
            }}
          >
            <View style={styles.emojiPickerContainer}>
              <View style={[styles.emojiPickerContent, { backgroundColor: colors.card }]}>
                <Text style={[styles.emojiPickerTitle, { color: colors.text }]}>Add Reaction</Text>
                <View style={styles.emojiGrid}>
                  {['👍', '❤️', '😂', '😮', '😢', '🎉', '👏', '🔥', '💯', '🙏', '😍', '🤔'].map((emoji) => (
                    <TouchableOpacity
                      key={emoji}
                      style={[styles.emojiButton, { backgroundColor: colors.backgroundGray }]}
                      onPress={() => handleReaction(emoji)}
                    >
                      <Text style={styles.emojiText}>{emoji}</Text>
                    </TouchableOpacity>
                  ))}
                </View>
              </View>
            </View>
          </TouchableOpacity>
        </Modal>

        {/* Forward Modal */}
        <Modal
          visible={showForwardModal}
          transparent={true}
          animationType="slide"
          onRequestClose={() => {
            setShowForwardModal(false);
            setForwardingMessage(null);
            setContactsSearchQuery('');
          }}
        >
          <View style={styles.modalOverlay}>
            <View style={[styles.modalContent, { backgroundColor: colors.card }]}>
              {/* Modal Header */}
              <View style={[styles.modalHeader, { borderBottomColor: colors.border }]}>
                <Text style={[styles.modalTitle, { color: colors.text }]}>Forward Message</Text>
                <TouchableOpacity
                  style={[styles.modalCloseButton, { backgroundColor: colors.border }]}
                  onPress={() => {
                    setShowForwardModal(false);
                    setForwardingMessage(null);
                    setContactsSearchQuery('');
                  }}
                >
                  <Ionicons name="close" size={24} color={colors.text} />
                </TouchableOpacity>
              </View>

              {/* Forward Preview */}
              {forwardingMessage && (
                <View style={[styles.forwardPreview, { backgroundColor: colors.backgroundGray }]}>
                  <Ionicons name="arrow-forward" size={16} color={colors.primary} />
                  <Text style={[styles.forwardPreviewText, { color: colors.textSecondary }]} numberOfLines={2}>
                    {forwardingMessage.content || (forwardingMessage.type === 'image' ? '📷 Image' : '📎 File')}
                  </Text>
                </View>
              )}

              {/* Search Bar */}
              <View style={[styles.modalSearchBar, { backgroundColor: colors.backgroundGray, borderColor: colors.border }]}>
                <Ionicons name="search" size={18} color={colors.textSecondary} />
                <TextInput
                  style={[styles.modalSearchInput, { color: colors.text }]}
                  value={contactsSearchQuery}
                  onChangeText={setContactsSearchQuery}
                  placeholder="Search contacts..."
                  placeholderTextColor={colors.textSecondary}
                />
                {contactsSearchQuery.length > 0 && (
                  <TouchableOpacity onPress={() => setContactsSearchQuery('')}>
                    <Ionicons name="close-circle" size={18} color={colors.textSecondary} />
                  </TouchableOpacity>
                )}
              </View>

              {/* Contacts List */}
              <ScrollView
                style={styles.modalContactsList}
                showsVerticalScrollIndicator={false}
              >
                {loadingContacts ? (
                  <View style={styles.modalLoadingContainer}>
                    <ActivityIndicator size="large" color={colors.primary} />
                  </View>
                ) : (
                  <>
                    {/* Staff Section */}
                    {availableContacts.staff.length > 0 && (
                      <View style={styles.contactSection}>
                        <Text style={[styles.contactSectionTitle, { color: colors.textSecondary }]}>Staff</Text>
                        {availableContacts.staff
                          .filter(s =>
                            s.name.toLowerCase().includes(contactsSearchQuery.toLowerCase()) ||
                            s.role?.toLowerCase().includes(contactsSearchQuery.toLowerCase())
                          )
                          .map(staff => (
                            <TouchableOpacity
                              key={staff.id}
                              style={[styles.contactItem, { backgroundColor: colors.card }]}
                              onPress={() => handleForward(staff.id, 'staff')}
                            >
                              <View style={[styles.contactAvatar, { backgroundColor: colors.primary + '15' }]}>
                                <Text style={[styles.contactAvatarText, { color: colors.primary }]}>
                                  {staff.name.charAt(0).toUpperCase()}
                                </Text>
                              </View>
                              <View style={styles.contactInfo}>
                                <Text style={[styles.contactName, { color: colors.text }]}>{staff.name}</Text>
                                {staff.role && (
                                  <Text style={[styles.contactRole, { color: colors.textSecondary }]}>{staff.role}</Text>
                                )}
                              </View>
                              <Ionicons name="arrow-forward" size={20} color={colors.primary} />
                            </TouchableOpacity>
                          ))}
                      </View>
                    )}

                    {/* Students Section */}
                    {availableContacts.students.length > 0 && (
                      <View style={styles.contactSection}>
                        <Text style={[styles.contactSectionTitle, { color: colors.textSecondary }]}>Students</Text>
                        {availableContacts.students
                          .filter(s =>
                            s.name.toLowerCase().includes(contactsSearchQuery.toLowerCase())
                          )
                          .map(student => (
                            <TouchableOpacity
                              key={student.id}
                              style={[styles.contactItem, { backgroundColor: colors.card }]}
                              onPress={() => handleForward(student.id, 'student')}
                            >
                              <View style={[styles.contactAvatar, styles.studentAvatar, { backgroundColor: colors.primary + '15' }]}>
                                <Text style={[styles.contactAvatarText, { color: colors.primary }]}>
                                  {student.name.charAt(0).toUpperCase()}
                                </Text>
                              </View>
                              <View style={styles.contactInfo}>
                                <Text style={[styles.contactName, { color: colors.text }]}>{student.name}</Text>
                                {student.rollNo && (
                                  <Text style={[styles.contactRole, { color: colors.textSecondary }]}>Roll No: {student.rollNo}</Text>
                                )}
                              </View>
                              <Ionicons name="arrow-forward" size={20} color={colors.primary} />
                            </TouchableOpacity>
                          ))}
                      </View>
                    )}
                  </>
                )}
              </ScrollView>
            </View>
          </View>
        </Modal>
      </View>
    );
  }

  // Conversations List screen
  return (
    <>
      <View style={[styles.container, { backgroundColor: colors.backgroundGray }]}>
        <StatusBar barStyle={activeTheme === 'dark' ? 'light-content' : 'dark-content'} backgroundColor={colors.backgroundGray} />

        {/* Header */}
        <View style={[styles.listHeader, { backgroundColor: colors.backgroundGray, borderBottomColor: colors.border }]}>
          <View style={styles.listHeaderTop}>
            <View>
              <Text style={[styles.listHeaderGreeting, { color: colors.text }]}>Messages</Text>
              <Text style={[styles.listHeaderSubtitle, { color: colors.textSecondary }]}>
                {totalUnread} unread messages
              </Text>
            </View>
          </View>

          {/* Search Bar */}
          <View style={[styles.searchBar, { backgroundColor: colors.card, borderColor: colors.border }]}>
            <Ionicons name="search" size={18} color={colors.textSecondary} />
            <TextInput
              style={[styles.searchInput, { color: colors.text }]}
              value={searchQuery}
              onChangeText={setSearchQuery}
              placeholder="Search conversations..."
              placeholderTextColor={colors.textSecondary}
            />
            {searchQuery.length > 0 && (
              <TouchableOpacity onPress={() => setSearchQuery('')}>
                <Ionicons name="close-circle" size={18} color={colors.textSecondary} />
              </TouchableOpacity>
            )}
          </View>
        </View>

        {/* Conversations List */}
        <ScrollView
          style={styles.conversationsContainer}
          contentContainerStyle={styles.conversationsContent}
          showsVerticalScrollIndicator={false}
        >
          {loading ? (
            <View style={styles.loadingContainer}>
              <ActivityIndicator size="large" color={colors.primary} />
            </View>
          ) : filteredConversations.length === 0 ? (
            <View style={styles.emptyState}>
              <View style={[styles.emptyIconContainer, { backgroundColor: colors.primary + '10' }]}>
                <Ionicons name="chatbubbles-outline" size={48} color={colors.primary} />
              </View>
              <Text style={[styles.emptyTitle, { color: colors.text }]}>No conversations</Text>
              <Text style={[styles.emptySubtitle, { color: colors.textSecondary }]}>Start a new conversation with your colleagues or parents</Text>
            </View>
          ) : (
            <>
              {/* Pinned Conversations */}
              {filteredConversations.some(c => c.unreadCount && c.unreadCount > 0) && (
                <View style={styles.sectionHeader}>
                  <Ionicons name="pin" size={14} color={colors.primary} />
                  <Text style={[styles.sectionTitle, { color: colors.textSecondary }]}>Priority</Text>
                </View>
              )}
              {filteredConversations
                .filter(c => c.unreadCount && c.unreadCount > 0)
                .map((conversation) => (
                  <ConversationItem
                    key={conversation.id}
                    conversation={conversation}
                    onPress={() => loadMessages(conversation)}
                    colors={colors}
                  />
                ))}

              {/* All Conversations */}
              <View style={styles.sectionHeader}>
                <Ionicons name="chatbubbles" size={14} color={colors.textSecondary} />
                <Text style={[styles.sectionTitle, { color: colors.textSecondary }]}>All Messages</Text>
              </View>
              {filteredConversations
                .filter(c => !c.unreadCount || c.unreadCount === 0)
                .map((conversation) => (
                  <ConversationItem
                    key={conversation.id}
                    conversation={conversation}
                    onPress={() => loadMessages(conversation)}
                    colors={colors}
                  />
                ))}
            </>
          )}
          <View style={styles.bottomPadding} />
        </ScrollView>

        {/* Floating Action Button */}
        <FloatingButton onPress={() => setShowNewChatModal(true)} colors={colors} />
      </View>

      {/* New Chat Modal */}
      <Modal
        visible={showNewChatModal}
        animationType="slide"
        transparent={true}
        onRequestClose={() => setShowNewChatModal(false)}
      >
        <View style={styles.modalOverlay}>
          <View style={[styles.modalContent, { backgroundColor: colors.card }]}>
            {/* Modal Header */}
            <View style={[styles.modalHeader, { borderBottomColor: colors.border }]}>
              <Text style={[styles.modalTitle, { color: colors.text }]}>New Conversation</Text>
              <TouchableOpacity
                style={[styles.modalCloseButton, { backgroundColor: colors.border }]}
                onPress={() => setShowNewChatModal(false)}
              >
                <Ionicons name="close" size={24} color={colors.text} />
              </TouchableOpacity>
            </View>

            {/* Search Bar */}
            <View style={[styles.modalSearchBar, { backgroundColor: colors.backgroundGray, borderColor: colors.border }]}>
              <Ionicons name="search" size={18} color={colors.textSecondary} />
              <TextInput
                style={[styles.modalSearchInput, { color: colors.text }]}
                value={contactsSearchQuery}
                onChangeText={setContactsSearchQuery}
                placeholder="Search contacts..."
                placeholderTextColor={colors.textSecondary}
              />
              {contactsSearchQuery.length > 0 && (
                <TouchableOpacity onPress={() => setContactsSearchQuery('')}>
                  <Ionicons name="close-circle" size={18} color={colors.textSecondary} />
                </TouchableOpacity>
              )}
            </View>

            {/* Contacts List */}
            <ScrollView
              style={styles.modalContactsList}
              showsVerticalScrollIndicator={false}
            >
              {loadingContacts ? (
                <View style={styles.modalLoadingContainer}>
                  <ActivityIndicator size="large" color={colors.primary} />
                </View>
              ) : (
                <>
                  {/* Staff Section */}
                  {availableContacts.staff.length > 0 && (
                    <View style={styles.contactSection}>
                      <Text style={[styles.contactSectionTitle, { color: colors.textSecondary }]}>Staff</Text>
                      {availableContacts.staff
                        .filter(s =>
                          s.name.toLowerCase().includes(contactsSearchQuery.toLowerCase()) ||
                          s.role?.toLowerCase().includes(contactsSearchQuery.toLowerCase())
                        )
                        .map(staff => (
                          <TouchableOpacity
                            key={staff.id}
                            style={[styles.contactItem, { backgroundColor: colors.card }]}
                            onPress={() => startConversation(staff.id, 'staff')}
                          >
                            <View style={[styles.contactAvatar, { backgroundColor: colors.primary + '15' }]}>
                              <Text style={[styles.contactAvatarText, { color: colors.primary }]}>
                                {staff.name.charAt(0).toUpperCase()}
                              </Text>
                            </View>
                            <View style={styles.contactInfo}>
                              <Text style={[styles.contactName, { color: colors.text }]}>{staff.name}</Text>
                              {staff.role && (
                                <Text style={[styles.contactRole, { color: colors.textSecondary }]}>{staff.role}</Text>
                              )}
                            </View>
                            <Ionicons name="chevron-forward" size={20} color={colors.textSecondary} />
                          </TouchableOpacity>
                        ))}
                    </View>
                  )}

                  {/* Students Section */}
                  {availableContacts.students.length > 0 && (
                    <View style={styles.contactSection}>
                      <Text style={[styles.contactSectionTitle, { color: colors.textSecondary }]}>Students</Text>
                      {availableContacts.students
                        .filter(s =>
                          s.name.toLowerCase().includes(contactsSearchQuery.toLowerCase())
                        )
                        .map(student => (
                          <TouchableOpacity
                            key={student.id}
                            style={[styles.contactItem, { backgroundColor: colors.card }]}
                            onPress={() => startConversation(student.id, 'student')}
                          >
                            <View style={[styles.contactAvatar, styles.studentAvatar, { backgroundColor: colors.primary + '15' }]}>
                              <Text style={[styles.contactAvatarText, { color: colors.primary }]}>
                                {student.name.charAt(0).toUpperCase()}
                              </Text>
                            </View>
                            <View style={styles.contactInfo}>
                              <Text style={[styles.contactName, { color: colors.text }]}>{student.name}</Text>
                              {student.rollNo && (
                                <Text style={[styles.contactRole, { color: colors.textSecondary }]}>Roll No: {student.rollNo}</Text>
                              )}
                            </View>
                            <Ionicons name="chevron-forward" size={20} color={colors.textSecondary} />
                          </TouchableOpacity>
                        ))}
                    </View>
                  )}

                  {/* Empty State */}
                  {!loadingContacts &&
                    availableContacts.staff.length === 0 &&
                    availableContacts.students.length === 0 && (
                      <View style={styles.modalEmptyState}>
                        <Ionicons name="people" size={48} color={colors.textSecondary} />
                        <Text style={[styles.modalEmptyText, { color: colors.textSecondary }]}>No contacts available</Text>
                      </View>
                    )}
                </>
              )}
            </ScrollView>
          </View>
        </View>
      </Modal>
    </>
  );
}

