import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  Dimensions,
  Animated,
  Modal,
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useTheme } from '../context/ThemeContext';

const { width: SCREEN_WIDTH, height: SCREEN_HEIGHT } = Dimensions.get('window');

// Tab bar measurements (approximate for this tab bar design)
const TAB_BAR_HEIGHT = 80;
const TAB_ITEM_WIDTH = SCREEN_WIDTH / 4;

export interface TourStep {
  id: string;
  tabIndex: number; // 0, 1, 2, 3 for the 4 tabs
  title: string;
  description: string;
  iconName: keyof typeof Ionicons.glyphMap;
}

interface GuidedTourProps {
  visible: boolean;
  steps: TourStep[];
  currentStepIndex: number;
  onClose: () => void;
  onNext: () => void;
}

// Tour steps explaining each tab
export const DEFAULT_TOUR_STEPS: TourStep[] = [
  {
    id: '1',
    tabIndex: 0,
    title: 'Dashboard',
    description: 'View your daily overview, attendance, schedule, and quick actions',
    iconName: 'home',
  },
  {
    id: '2',
    tabIndex: 1,
    title: 'Timetable',
    description: 'Check your class schedule and manage substitutions',
    iconName: 'calendar-clear',
  },
  {
    id: '3',
    tabIndex: 2,
    title: 'Chat',
    description: 'Communicate with parents, students, and staff members',
    iconName: 'chatbubbles',
  },
  {
    id: '4',
    tabIndex: 3,
    title: 'Profile',
    description: 'Manage your profile, view payslips, and apply for leave',
    iconName: 'person-circle',
  },
];

export default function GuidedTour({
  visible,
  steps,
  currentStepIndex,
  onClose,
  onNext,
}: GuidedTourProps) {
  const { colors } = useTheme();
  const [fadeAnim] = useState(new Animated.Value(0));
  const [slideAnim] = useState(new Animated.Value(50));

  const currentStep = steps[currentStepIndex];
  const isLastStep = currentStepIndex === steps.length - 1;

  useEffect(() => {
    if (visible && currentStep) {
      // Reset animations
      fadeAnim.setValue(0);
      slideAnim.setValue(50);

      // Animate in
      Animated.parallel([
        Animated.timing(fadeAnim, {
          toValue: 1,
          duration: 300,
          useNativeDriver: true,
        }),
        Animated.timing(slideAnim, {
          toValue: 0,
          duration: 300,
          useNativeDriver: true,
        }),
      ]).start();
    }
  }, [visible, currentStepIndex, currentStep]);

  const handleNext = () => {
    // Animate out
    Animated.parallel([
      Animated.timing(fadeAnim, {
        toValue: 0,
        duration: 200,
        useNativeDriver: true,
      }),
      Animated.timing(slideAnim, {
        toValue: 50,
        duration: 200,
        useNativeDriver: true,
      }),
    ]).start(() => {
      onNext();
    });
  };

  const handleClose = () => {
    Animated.timing(fadeAnim, {
      toValue: 0,
      duration: 200,
      useNativeDriver: true,
    }).start(() => {
      onClose();
    });
  };

  if (!currentStep) return null;

  // Calculate position for the highlight (centered on the tab item)
  const highlightX = currentStep.tabIndex * TAB_ITEM_WIDTH + TAB_ITEM_WIDTH / 2;

  return (
    <Modal visible={visible} transparent animationType="none">
      <View style={styles.container}>
        {/* Dark overlay with cutout for the highlighted tab */}
        <View style={styles.overlay}>
          {/* Top dark area */}
          <View style={styles.topOverlay} />

          {/* Middle section with cutout */}
          <View style={styles.middleSection}>
            {/* Left dark area */}
            <View style={[styles.sideOverlay, { width: highlightX - 35 }]} />

            {/* Transparent cutout area */}
            <View style={styles.cutout}>
              {/* Glow effect around the highlighted tab */}
              <View style={styles.glowRing}>
                <View style={[styles.iconContainer, { backgroundColor: colors.white, shadowColor: colors.primary }]}>
                  <Ionicons
                    name={currentStep.iconName}
                    size={32}
                    color={colors.primary}
                  />
                </View>
              </View>
              {/* Pulsing animation indicator */}
              <View style={styles.pulseIndicator} />
            </View>

            {/* Right dark area */}
            <View style={[styles.sideOverlay, { flex: 1 }]} />
          </View>

          {/* Bottom dark area */}
          <View style={styles.bottomOverlay} />
        </View>

        {/* Tooltip card - positioned above the highlighted tab */}
        <Animated.View 
          style={[
            styles.tooltipCard,
            {
              opacity: fadeAnim,
              transform: [{ translateY: slideAnim }],
            },
          ]}
        >
          {/* Arrow pointing down to the tab */}
          <View style={styles.arrow} />

          {/* Close button */}
          <TouchableOpacity style={styles.closeButton} onPress={handleClose}>
            <Ionicons name="close" size={24} color="#6B7280" />
          </TouchableOpacity>

          {/* Icon */}
          <View style={[styles.tooltipIconContainer, { backgroundColor: colors.primary + '0F' }]}>
            <Ionicons name={currentStep.iconName} size={40} color={colors.primary} />
          </View>

          {/* Title */}
          <Text style={styles.title}>{currentStep.title}</Text>

          {/* Description */}
          <Text style={styles.description}>{currentStep.description}</Text>

          {/* Footer with dots and Next button */}
          <View style={styles.footer}>
            {/* Pagination dots */}
            <View style={styles.dotsContainer}>
              {steps.map((_, index) => (
                <View
                  key={index}
                  style={[
                    styles.dot,
                    index === currentStepIndex && styles.activeDot,
                  ]}
                />
              ))}
            </View>

            {/* Next/Done button */}
            <TouchableOpacity style={styles.nextButton} onPress={handleNext}>
              <Text style={styles.nextButtonText}>
                {isLastStep ? 'Done' : 'Next'}
              </Text>
            </TouchableOpacity>
          </View>
        </Animated.View>

        {/* Skip button at top */}
        <TouchableOpacity style={styles.skipButton} onPress={handleClose}>
          <Text style={styles.skipText}>Skip Tour</Text>
        </TouchableOpacity>
      </View>
    </Modal>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  overlay: {
    ...StyleSheet.absoluteFillObject,
  },
  topOverlay: {
    height: SCREEN_HEIGHT - TAB_BAR_HEIGHT - 20,
    backgroundColor: 'rgba(0, 0, 0, 0.75)',
  },
  middleSection: {
    flexDirection: 'row',
    height: 80,
  },
  sideOverlay: {
    backgroundColor: 'rgba(0, 0, 0, 0.75)',
  },
  cutout: {
    width: 70,
    height: 80,
    backgroundColor: 'transparent',
    justifyContent: 'center',
    alignItems: 'center',
  },
  glowRing: {
    width: 70,
    height: 70,
    borderRadius: 35,
    backgroundColor: 'rgba(227, 28, 95, 0.2)',
    justifyContent: 'center',
    alignItems: 'center',
  },
  iconContainer: {
    width: 56,
    height: 56,
    borderRadius: 28,
    justifyContent: 'center',
    alignItems: 'center',
    shadowOffset: { width: 0, height: 0 },
    shadowOpacity: 0.5,
    shadowRadius: 10,
    elevation: 10,
  },
  pulseIndicator: {
    position: 'absolute',
    width: 80,
    height: 80,
    borderRadius: 40,
    borderWidth: 2,
    borderColor: 'rgba(227, 28, 95, 0.4)',
  },
  bottomOverlay: {
    flex: 1,
    backgroundColor: 'rgba(0, 0, 0, 0.75)',
  },
  tooltipCard: {
    position: 'absolute',
    left: 20,
    right: 20,
    bottom: TAB_BAR_HEIGHT + 40,
    borderRadius: 20,
    padding: 24,
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 10 },
    shadowOpacity: 0.3,
    shadowRadius: 20,
    elevation: 20,
  },
  arrow: {
    position: 'absolute',
    bottom: -10,
    left: '50%',
    marginLeft: -10,
    width: 0,
    height: 0,
    backgroundColor: 'transparent',
    borderStyle: 'solid',
    borderLeftWidth: 10,
    borderRightWidth: 10,
    borderTopWidth: 10,
    borderLeftColor: 'transparent',
    borderRightColor: 'transparent',
  },
  closeButton: {
    position: 'absolute',
    top: 16,
    right: 16,
    padding: 4,
  },
  tooltipIconContainer: {
    width: 70,
    height: 70,
    borderRadius: 20,
    justifyContent: 'center',
    alignItems: 'center',
    alignSelf: 'center',
    marginBottom: 16,
  },
  title: {
    fontSize: 22,
    fontWeight: '700',
    textAlign: 'center',
    marginBottom: 8,
  },
  description: {
    fontSize: 15,
    textAlign: 'center',
    lineHeight: 22,
    marginBottom: 20,
  },
  footer: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginTop: 8,
  },
  dotsContainer: {
    flexDirection: 'row',
    gap: 8,
  },
  dot: {
    width: 8,
    height: 8,
    borderRadius: 4,
  },
  activeDot: {
    width: 16,
  },
  nextButton: {
    paddingVertical: 8,
    paddingHorizontal: 4,
  },
  nextButtonText: {
    fontSize: 16,
    fontWeight: '600',
  },
  skipButton: {
    position: 'absolute',
    top: 50,
    right: 20,
    padding: 12,
  },
  skipText: {
    fontSize: 14,
    fontWeight: '600',
  },
});

