  StyleSheet,
  Dimensions,
  Image,
  ImageSourcePropType,
} from 'react-native';
import { Ionicons } from '@expo/vector-icons';

const { width: SCREEN_WIDTH } = Dimensions.get('window');

export interface ExplainerSlide {
  id: string;
  illustration?: ImageSourcePropType;
  illustrationType?: 'image' | 'emoji' | 'icon';
  emoji?: string;
  iconName?: keyof typeof Ionicons.glyphMap;
  iconColor?: string;
  title: string;
  description: string;
}

interface SectionExplainerProps {
  visible: boolean;
  slides: ExplainerSlide[];
  currentSlideIndex: number;
  onClose: () => void;
  onNext: () => void;
  onSlideChange?: (index: number) => void;
}

export default function SectionExplainer({
  visible,
  slides,
  currentSlideIndex,
  onClose,
  onNext,
  onSlideChange,
}: SectionExplainerProps) {
  const currentSlide = slides[currentSlideIndex];
  const isLastSlide = currentSlideIndex === slides.length - 1;

  const handleNext = () => {
    if (isLastSlide) {
      onClose();
    } else {
      onNext();
    }
  };

  const handleDotPress = (index: number) => {
    onSlideChange?.(index);
  };

  const renderIllustration = () => {
    if (!currentSlide) return null;

    const { illustrationType, illustration, emoji, iconName, iconColor } = currentSlide;

    if (illustrationType === 'image' && illustration) {
      return <Image source={illustration} style={styles.illustrationImage} resizeMode="contain" />;
    }

    if (illustrationType === 'emoji' && emoji) {
      return <Text style={styles.emoji}>{emoji}</Text>;
    }

    if (illustrationType === 'icon' && iconName) {
      return (
        <View style={[styles.iconContainer, { backgroundColor: iconColor || '#3B82F6' }]}>
          <Ionicons name={iconName} size={64} color="#FFFFFF" />
        </View>
      );
    }

    // Default: chat bubble illustration similar to reference
    return (
      <View style={styles.defaultIllustration}>
        <View style={styles.chatBubble}>
          <View style={styles.chatBubbleInner}>
            <View style={styles.dotsContainer}>
              <View style={styles.dot} />
              <View style={styles.dot} />
              <View style={styles.dot} />
            </View>
          </View>
          <View style={styles.chatBubbleTail} />
        </View>
        <View style={styles.platform} />
      </View>
    );
  };

  if (!currentSlide) return null;

  return (
    <Modal visible={visible} transparent animationType="fade">
      <View style={styles.overlay}>
        <View style={styles.card}>
          {/* Close Button */}
          <TouchableOpacity style={styles.closeButton} onPress={onClose}>
            <Ionicons name="close" size={28} color="#6B7280" />
          </TouchableOpacity>

          {/* Illustration */}
          <View style={styles.illustrationContainer}>{renderIllustration()}</View>

          {/* Content */}
          <View style={styles.content}>
            <Text style={styles.title}>{currentSlide.title}</Text>
            <Text style={styles.description}>{currentSlide.description}</Text>
          </View>

          {/* Footer */}
          <View style={styles.footer}>
            {/* Pagination Dots */}
            <View style={styles.dotsRow}>
              {slides.map((_, index) => (
                <TouchableOpacity
                  key={index}
                  onPress={() => handleDotPress(index)}
                  style={[
                    styles.paginationDot,
                    index === currentSlideIndex && styles.paginationDotActive,
                  ]}
                />
              ))}
            </View>

            {/* Next Button */}
            <TouchableOpacity style={styles.nextButton} onPress={handleNext}>
              <Text style={styles.nextButtonText}>
                {isLastSlide ? 'Done' : 'Next'}
              </Text>
            </TouchableOpacity>
          </View>
        </View>
      </View>
    </Modal>
  );
}

