import React from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  SafeAreaView,
  StatusBar,
} from 'react-native';
import { useRouter } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import { useTheme } from '../context/ThemeContext';

type ThemeOption = 'light' | 'dark' | 'system';

interface ThemeOptionConfig {
  id: ThemeOption;
  label: string;
  description: string;
  icon: string;
}

const themeOptions: ThemeOptionConfig[] = [
  {
    id: 'light',
    label: 'Light',
    description: 'Always use light mode',
    icon: 'sunny-outline',
  },
  {
    id: 'dark',
    label: 'Dark',
    description: 'Always use dark mode',
    icon: 'moon-outline',
  },
  {
    id: 'system',
    label: 'System',
    description: 'Match your device settings',
    icon: 'phone-portrait-outline',
  },
];

export default function ThemeSettingsScreen() {
  const router = useRouter();
  const { theme, setTheme, activeTheme, colors } = useTheme();

  const handleThemeSelect = (selectedTheme: ThemeOption) => {
    setTheme(selectedTheme);
  };

  return (
    <SafeAreaView style={[styles.container, { backgroundColor: colors.background }]}>
      <StatusBar barStyle={colors.background === '#FFFFFF' ? 'dark-content' : 'light-content'} backgroundColor={colors.background} />

      {/* Header */}
      <View style={[styles.header, { backgroundColor: colors.background, borderBottomColor: colors.border }]}>
        <TouchableOpacity onPress={() => router.back()} style={styles.backButton}>
          <Ionicons name="arrow-back" size={24} color={colors.text} />
        </TouchableOpacity>
        <Text style={[styles.headerTitle, { color: colors.text }]}>Theme</Text>
        <View style={styles.headerSpacer} />
      </View>

      <ScrollView style={[styles.scrollView, { backgroundColor: colors.backgroundGray }]} showsVerticalScrollIndicator={false}>
        {/* Info Banner */}
        <View style={[styles.infoBanner, { backgroundColor: colors.primary + '15' }]}>
          <Ionicons name="information-circle-outline" size={20} color={colors.primary} />
          <Text style={[styles.infoBannerText, { color: colors.text }]}>
            Choose your preferred theme appearance
          </Text>
        </View>

        {/* Theme Options */}
        <View style={styles.section}>
          <Text style={[styles.sectionTitle, { color: colors.text }]}>Select Theme</Text>
          <View style={[styles.card, { backgroundColor: colors.card }]}>
            {themeOptions.map((option, index) => (
              <ThemeOptionItem
                key={option.id}
                option={option}
                isSelected={theme === option.id}
                onPress={() => handleThemeSelect(option.id)}
                colors={colors}
                isLast={index === themeOptions.length - 1}
              />
            ))}
          </View>
        </View>

        {/* Preview Section */}
        <View style={styles.section}>
          <Text style={[styles.sectionTitle, { color: colors.text }]}>Preview</Text>
          <View style={[styles.card, { backgroundColor: colors.card }]}>
            <View style={[styles.previewRow, { borderBottomColor: colors.border }]}>
              <View style={styles.previewLeft}>
                <View style={[styles.previewDot, { backgroundColor: colors.primary }]} />
                <Text style={[styles.previewLabel, { color: colors.text }]}>Primary Color</Text>
              </View>
              <Text style={[styles.previewValue, { color: colors.primary }]}>{colors.primary}</Text>
            </View>
            <View style={[styles.previewRow, { borderBottomColor: colors.border }]}>
              <View style={styles.previewLeft}>
                <View style={[styles.previewDot, { backgroundColor: colors.text }]} />
                <Text style={[styles.previewLabel, { color: colors.text }]}>Text Color</Text>
              </View>
              <Text style={[styles.previewValue, { color: colors.text }]}>{colors.text}</Text>
            </View>
            <View style={[styles.previewRow, { borderBottomColor: colors.border }]}>
              <View style={styles.previewLeft}>
                <View style={[styles.previewDot, { backgroundColor: colors.background }]} />
                <Text style={[styles.previewLabel, { color: colors.text }]}>Background</Text>
              </View>
              <Text style={[styles.previewValue, { color: colors.textSecondary }]}>{colors.background}</Text>
            </View>
            <View style={styles.previewRow}>
              <View style={styles.previewLeft}>
                <View style={[styles.previewDot, { backgroundColor: colors.card }]} />
                <Text style={[styles.previewLabel, { color: colors.text }]}>Card Background</Text>
              </View>
              <Text style={[styles.previewValue, { color: colors.textSecondary }]}>{colors.card}</Text>
            </View>
          </View>
        </View>

        {/* Current Active Info */}
        <View style={[styles.activeBanner, { backgroundColor: colors.success + '15', borderBottomColor: colors.success }]}>
          <Ionicons name="checkmark-circle" size={20} color={colors.success} />
          <Text style={[styles.activeBannerText, { color: colors.text }]}>
            Currently using: <Text style={{ fontWeight: '600' }}>{activeTheme === 'dark' ? 'Dark' : 'Light'} mode</Text>
          </Text>
        </View>

        {/* Bottom spacing */}
        <View style={styles.bottomSpacing} />
      </ScrollView>
    </SafeAreaView>
  );
}

function ThemeOptionItem({
  option,
  isSelected,
  onPress,
  colors,
  isLast,
}: {
  option: ThemeOptionConfig;
  isSelected: boolean;
  onPress: () => void;
  colors: any;
  isLast: boolean;
}) {
  return (
    <TouchableOpacity
      style={[styles.optionRow, !isLast && styles.optionRowBorder]}
      onPress={onPress}
      activeOpacity={0.7}
    >
      <View style={styles.optionLeft}>
        <View style={[styles.optionIconContainer, { backgroundColor: isSelected ? colors.primary + '20' : colors.inputBackground }]}>
          <Ionicons
            name={option.icon as any}
            size={22}
            color={isSelected ? colors.primary : colors.textSecondary}
          />
        </View>
        <View style={styles.optionInfo}>
          <Text style={[styles.optionLabel, { color: colors.text }]}>{option.label}</Text>
          <Text style={[styles.optionDescription, { color: colors.textSecondary }]}>{option.description}</Text>
        </View>
      </View>
      {isSelected && (
        <View style={[styles.checkCircle, { backgroundColor: colors.primary }]}>
          <Ionicons name="checkmark" size={18} color="#FFFFFF" />
        </View>
      )}
    </TouchableOpacity>
  );
}

