import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  ScrollView,
  StyleSheet,
  TouchableOpacity,
  Alert,
  ActivityIndicator,
  Modal,
} from 'react-native';
import { useRouter } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import { useForm, useFieldArray, Control, FieldValues } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';

import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { useStaffProfile } from '../hooks/useStaffProfile';
import { ProfileFormField } from '../components/ProfileFormField';
import { EmergencyContactItem } from '../components/EmergencyContactItem';
import SyncIndicator from '../components/SyncIndicator';
import { profileUpdateSchema, ProfileUpdateFormData } from '../services/validation';
import api from '../services/api';

// Constants for picker options
const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'] as const;
const MARITAL_STATUSES = ['Single', 'Married', 'Divorced', 'Widowed'] as const;

export default function EditProfileScreen() {
  const router = useRouter();
  const { user } = useAuth();
  const { colors } = useTheme();
  const { profile, syncStatus, isLoading, refetch } = useStaffProfile();
  const [isSaving, setIsSaving] = useState(false);
  const [showBloodGroupPicker, setShowBloodGroupPicker] = useState(false);
  const [showMaritalStatusPicker, setShowMaritalStatusPicker] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  // Form setup with validation
  const {
    control,
    handleSubmit,
    setValue,
    reset,
    formState: { isDirty, errors, isValid, dirtyFields },
  } = useForm<ProfileUpdateFormData>({
    resolver: zodResolver(profileUpdateSchema),
    defaultValues: {
      phone: '',
      email: '',
      whatsappNumber: '',
      bloodGroup: undefined,
      maritalStatus: undefined,
      address: '',
      emergencyContacts: [
        {
          name: '',
          relationship: '',
          phone: '',
        },
      ],
    },
    mode: 'all', // Validate on blur and change
  });

  // Emergency contacts array management
  const { fields, append, remove } = useFieldArray({
    control,
    name: 'emergencyContacts',
  });

  // Reset form when profile loads
  useEffect(() => {
    if (profile) {
      console.log('Loading profile data:', profile);
      console.log('Emergency contacts:', profile.emergencyContacts);

      reset({
        phone: profile.phone || '',
        email: profile.email || '',
        whatsappNumber: profile.whatsappNumber || '',
        bloodGroup: profile.bloodGroup,
        maritalStatus: profile.maritalStatus,
        address: profile.address || '',
        emergencyContacts: profile.emergencyContacts && profile.emergencyContacts.length > 0
          ? profile.emergencyContacts.map((contact) => ({
              name: contact.name || '',
              relationship: contact.relationship || '',
              phone: contact.phone || '',
            }))
          : [{ name: '', relationship: '', phone: '' }],
      });
    }
  }, [profile, reset]);

  // Handle form submission
  const onSubmit = async (data: ProfileUpdateFormData) => {
    console.log('Form submitted with data:', data);
    console.log('Form isDirty:', isDirty);
    console.log('Form isValid:', isValid);
    console.log('Form errors:', errors);

    if (!user?.id) {
      setFormError('User not authenticated');
      return;
    }

    try {
      setIsSaving(true);
      setFormError(null);

      await api.updateStaffProfile(user.id, data);

      setSuccessMessage('Profile updated successfully');
      setTimeout(() => {
        refetch(); // Refresh profile data
        router.back();
      }, 1500);
    } catch (error: any) {
      console.error('Failed to update profile:', error);
      setFormError(error.message || 'Failed to update profile. Please try again.');
    } finally {
      setIsSaving(false);
    }
  };

  // Handle form submission with validation error display
  const handleSavePress = async () => {
    console.log('Save button pressed');
    console.log('isDirty:', isDirty);
    console.log('isValid:', isValid);
    console.log('errors:', errors);
    console.log('dirtyFields:', dirtyFields);

    setFormError(null);
    setSuccessMessage(null);

    // Check if form is dirty
    if (!isDirty) {
      setFormError('Please make some changes before saving.');
      return;
    }

    // If form is invalid, show errors
    if (!isValid) {
      console.log('Form is invalid, checking errors...');

      // Collect all error messages
      const errorMessages: string[] = [];

      // Check root-level errors
      if (errors.emergencyContacts?.message) {
        errorMessages.push(errors.emergencyContacts.message);
      }

      // Check field-level errors
      Object.entries(errors).forEach(([field, error]) => {
        if (error?.message && !field.startsWith('emergencyContacts.')) {
          errorMessages.push(`${field}: ${error.message}`);
        }
      });

      // Check emergency contact individual fields
      if (Array.isArray(errors.emergencyContacts)) {
        errors.emergencyContacts.forEach((contactError: any, index: number) => {
          if (contactError?.name?.message) {
            errorMessages.push(`Contact ${index + 1} - Name: ${contactError.name.message}`);
          }
          if (contactError?.relationship?.message) {
            errorMessages.push(`Contact ${index + 1} - Relationship: ${contactError.relationship.message}`);
          }
          if (contactError?.phone?.message) {
            errorMessages.push(`Contact ${index + 1} - Phone: ${contactError.phone.message}`);
          }
        });
      }

      console.log('Error messages:', errorMessages);

      if (errorMessages.length > 0) {
        setFormError('Please fix the validation errors: ' + errorMessages[0]);
      } else {
        setFormError('Please make sure all required fields are filled correctly:\n• Phone number (10 digits)\n• At least one complete emergency contact (name, relationship, phone)');
      }
      return;
    }

    // Form is valid, submit it
    handleSubmit((data) => {
      console.log('Validation passed, submitting...');
      onSubmit(data);
    })();
  };

  // Add emergency contact
  const handleAddContact = () => {
    setFormError(null);
    if (fields.length < 5) {
      append({ name: '', relationship: '', phone: '' });
    } else {
      setFormError('You can only add up to 5 emergency contacts');
    }
  };

  // Remove emergency contact
  const handleRemoveContact = (index: number) => {
    setFormError(null);
    if (fields.length > 1) {
      remove(index);
    } else {
      setFormError('At least one emergency contact is required');
    }
  };

  // Show loading state
  if (isLoading) {
    return (
      <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', backgroundColor: colors.backgroundGray }}>
        <ActivityIndicator size="large" color={colors.primary} />
        <Text style={{ marginTop: 12, fontSize: 16, color: colors.textSecondary }}>Loading profile...</Text>
      </View>
    );
  }

  return (
    <View style={{ flex: 1, backgroundColor: colors.backgroundGray }}>
      {/* Header */}
      <View style={{ flexDirection: 'row', alignItems: 'center', paddingHorizontal: 16, paddingVertical: 12, backgroundColor: colors.background, borderBottomWidth: 1, borderBottomColor: colors.border }}>
        <TouchableOpacity onPress={() => router.back()} style={{ padding: 4, marginRight: 12 }}>
          <Ionicons name="arrow-back" size={24} color={colors.text} />
        </TouchableOpacity>
        <Text style={{ flex: 1, fontSize: 20, fontWeight: '600', color: colors.text }}>Edit Profile</Text>
        <SyncIndicator status={syncStatus} />
      </View>

      <ScrollView
        style={{ flex: 1 }}
        contentContainerStyle={{ padding: 16 }}
        showsVerticalScrollIndicator={false}
      >
        {/* Contact Information Section */}
        <View style={{ backgroundColor: colors.card, borderRadius: 12, padding: 16, marginBottom: 16 }}>
          <Text style={{ fontSize: 18, fontWeight: '600', color: colors.text, marginBottom: 16 }}>Contact Information</Text>

          <ProfileFormField
            control={control}
            name="phone"
            label="Phone Number"
            required
            keyboardType="phone-pad"
            maxLength={10}
            error={errors.phone?.message}
          />

          <ProfileFormField
            control={control}
            name="email"
            label="Email Address"
            keyboardType="email-address"
            autoCapitalize="none"
            error={errors.email?.message}
          />

          <ProfileFormField
            control={control}
            name="whatsappNumber"
            label="WhatsApp Number"
            keyboardType="phone-pad"
            maxLength={10}
            error={errors.whatsappNumber?.message}
          />
        </View>

        {/* Personal Information Section */}
        <View style={{ backgroundColor: colors.card, borderRadius: 12, padding: 16, marginBottom: 16 }}>
          <Text style={{ fontSize: 18, fontWeight: '600', color: colors.text, marginBottom: 16 }}>Personal Information</Text>

          {/* Blood Group Picker */}
          <View style={{ marginBottom: 16 }}>
            <Text style={{ fontSize: 16, fontWeight: '500', color: colors.text, marginBottom: 8 }}>Blood Group</Text>
            <TouchableOpacity
              style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', backgroundColor: colors.backgroundGray, borderRadius: 8, borderWidth: 1, borderColor: colors.border, padding: 12 }}
              onPress={() => setShowBloodGroupPicker(true)}
            >
              <Text style={{ fontSize: 16, color: colors.text }}>
                {control._formValues.bloodGroup || 'Select Blood Group'}
              </Text>
              <Ionicons name="chevron-down" size={20} color={colors.textSecondary} />
            </TouchableOpacity>
            {errors.bloodGroup && (
              <Text style={{ color: '#FF3B30', fontSize: 12, marginTop: 4 }}>{errors.bloodGroup.message}</Text>
            )}
          </View>

          {/* Marital Status Picker */}
          <View style={{ marginBottom: 16 }}>
            <Text style={{ fontSize: 16, fontWeight: '500', color: colors.text, marginBottom: 8 }}>Marital Status</Text>
            <TouchableOpacity
              style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', backgroundColor: colors.backgroundGray, borderRadius: 8, borderWidth: 1, borderColor: colors.border, padding: 12 }}
              onPress={() => setShowMaritalStatusPicker(true)}
            >
              <Text style={{ fontSize: 16, color: colors.text }}>
                {control._formValues.maritalStatus || 'Select Marital Status'}
              </Text>
              <Ionicons name="chevron-down" size={20} color={colors.textSecondary} />
            </TouchableOpacity>
            {errors.maritalStatus && (
              <Text style={{ color: '#FF3B30', fontSize: 12, marginTop: 4 }}>{errors.maritalStatus.message}</Text>
            )}
          </View>

          <ProfileFormField
            control={control}
            name="address"
            label="Address"
            multiline
            numberOfLines={3}
            error={errors.address?.message}
          />
        </View>

        {/* Emergency Contacts Section */}
        <View style={{ backgroundColor: colors.card, borderRadius: 12, padding: 16, marginBottom: 16 }}>
          <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
            <Text style={{ fontSize: 18, fontWeight: '600', color: colors.text }}>Emergency Contacts</Text>
            <Text style={{ fontSize: 14, color: colors.textSecondary }}>
              {fields.length}/5 contacts
            </Text>
          </View>
          {errors.emergencyContacts && (
            <Text style={{ color: '#FF3B30', fontSize: 12 }}>{errors.emergencyContacts.message}</Text>
          )}

          {fields.map((field, index) => (
            <EmergencyContactItem
              key={field.id}
              control={control}
              name={`emergencyContacts.${index}` as any}
              onRemove={handleRemoveContact}
              canRemove={fields.length > 1}
            />
          ))}

          {fields.length < 5 && (
            <TouchableOpacity
              style={{ flexDirection: 'row', alignItems: 'center', justifyContent: 'center', padding: 12, borderRadius: 8, borderWidth: 1, borderColor: colors.primary, backgroundColor: 'transparent' }}
              onPress={handleAddContact}
            >
              <Ionicons name="add-circle" size={20} color={colors.primary} />
              <Text style={{ marginLeft: 8, fontSize: 16, fontWeight: '500', color: colors.primary }}>Add Emergency Contact</Text>
            </TouchableOpacity>
          )}
        </View>

        {/* Bottom spacing for footer */}
        <View style={{ height: 80 }} />
      </ScrollView>

      {/* Save Button Footer */}
      <View style={{ position: 'absolute', bottom: 0, left: 0, right: 0, backgroundColor: colors.card, paddingHorizontal: 16, paddingVertical: 12, borderTopWidth: 1, borderTopColor: colors.border }}>
        <TouchableOpacity
          style={[
            { flexDirection: 'row', alignItems: 'center', justifyContent: 'center', backgroundColor: colors.primary, borderRadius: 8, padding: 14 },
            (!isDirty || isSaving) && { backgroundColor: '#CCCCCC' },
          ]}
          onPress={handleSavePress}
          disabled={!isDirty || isSaving}
        >
          {isSaving ? (
            <ActivityIndicator color="#fff" />
          ) : (
            <>
              <Ionicons name="checkmark" size={20} color="#fff" />
              <Text style={{ marginLeft: 8, fontSize: 16, fontWeight: '600', color: '#fff' }}>Save Changes</Text>
            </>
          )}
        </TouchableOpacity>
      </View>

      {/* Blood Group Picker Modal */}
      <Modal
        visible={showBloodGroupPicker}
        transparent
        animationType="slide"
        onRequestClose={() => setShowBloodGroupPicker(false)}
      >
        <View style={{ flex: 1, justifyContent: 'flex-end', backgroundColor: 'rgba(0, 0, 0, 0.5)' }}>
          <View style={{ backgroundColor: colors.card, borderTopLeftRadius: 20, borderTopRightRadius: 20, paddingHorizontal: 16, paddingBottom: 24 }}>
            <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', paddingVertical: 16, borderBottomWidth: 1, borderBottomColor: colors.border, marginBottom: 8 }}>
              <Text style={{ fontSize: 18, fontWeight: '600', color: colors.text }}>Select Blood Group</Text>
              <TouchableOpacity onPress={() => setShowBloodGroupPicker(false)}>
                <Ionicons name="close" size={24} color={colors.text} />
              </TouchableOpacity>
            </View>
            {BLOOD_GROUPS.map((group) => (
              <TouchableOpacity
                key={group}
                style={[
                  { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', paddingVertical: 14, borderBottomWidth: 1, borderBottomColor: colors.backgroundGray },
                  control._formValues.bloodGroup === group && { backgroundColor: '#FFF5F7' },
                ]}
                onPress={() => {
                  setValue('bloodGroup', group);
                  setShowBloodGroupPicker(false);
                }}
              >
                <Text
                  style={[
                    { fontSize: 16, color: colors.text },
                    control._formValues.bloodGroup === group && { color: colors.primary, fontWeight: '500' },
                  ]}
                >
                  {group}
                </Text>
                {control._formValues.bloodGroup === group && (
                  <Ionicons name="checkmark" size={20} color={colors.primary} />
                )}
              </TouchableOpacity>
            ))}
          </View>
        </View>
      </Modal>

      {/* Marital Status Picker Modal */}
      <Modal
        visible={showMaritalStatusPicker}
        transparent
        animationType="slide"
        onRequestClose={() => setShowMaritalStatusPicker(false)}
      >
        <View style={{ flex: 1, justifyContent: 'flex-end', backgroundColor: 'rgba(0, 0, 0, 0.5)' }}>
          <View style={{ backgroundColor: colors.card, borderTopLeftRadius: 20, borderTopRightRadius: 20, paddingHorizontal: 16, paddingBottom: 24 }}>
            <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', paddingVertical: 16, borderBottomWidth: 1, borderBottomColor: colors.border, marginBottom: 8 }}>
              <Text style={{ fontSize: 18, fontWeight: '600', color: colors.text }}>Select Marital Status</Text>
              <TouchableOpacity onPress={() => setShowMaritalStatusPicker(false)}>
                <Ionicons name="close" size={24} color={colors.text} />
              </TouchableOpacity>
            </View>
            {MARITAL_STATUSES.map((status) => (
              <TouchableOpacity
                key={status}
                style={[
                  { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', paddingVertical: 14, borderBottomWidth: 1, borderBottomColor: colors.backgroundGray },
                  control._formValues.maritalStatus === status && { backgroundColor: '#FFF5F7' },
                ]}
                onPress={() => {
                  setValue('maritalStatus', status);
                  setShowMaritalStatusPicker(false);
                }}
              >
                <Text
                  style={[
                    { fontSize: 16, color: colors.text },
                    control._formValues.maritalStatus === status && { color: colors.primary, fontWeight: '500' },
                  ]}
                >
                  {status}
                </Text>
                {control._formValues.maritalStatus === status && (
                  <Ionicons name="checkmark" size={20} color={colors.primary} />
                )}
              </TouchableOpacity>
            ))}
          </View>
        </View>
      </Modal>
    </View>
  );
}

