import React, { useState } from 'react';
import {
  View,
  Text,
  Modal,
  TextInput,
  TouchableOpacity,
  StyleSheet,
  ScrollView,
  Alert,
  ActivityIndicator,
  Platform,
} from 'react-native';
import DateTimePicker, { DateTimePickerEvent } from '@react-native-community/datetimepicker';
import api from '../services/api';
import { format, addDays, parseISO, isValid } from 'date-fns';
import { useTheme } from '../context/ThemeContext';
import { Ionicons } from '@expo/vector-icons';

interface LeaveApplicationModalProps {
  visible: boolean;
  teacherId: string;
  onClose: () => void;
  onSuccess: () => void;
}

const LEAVE_TYPES = [
  { value: 'sick', label: 'Sick Leave' },
  { value: 'casual', label: 'Casual Leave' },
  { value: 'earned', label: 'Earned Leave' },
  { value: 'unpaid', label: 'Unpaid Leave' },
  { value: 'other', label: 'Other' },
];

export default function LeaveApplicationModal({
  visible,
  teacherId,
  onClose,
  onSuccess,
}: LeaveApplicationModalProps) {
  const { colors } = useTheme();
  const [leaveType, setLeaveType] = useState('casual');
  const [reason, setReason] = useState('');
  const [startDate, setStartDate] = useState(new Date());
  const [endDate, setEndDate] = useState(new Date());
  const [showStartDatePicker, setShowStartDatePicker] = useState(false);
  const [showEndDatePicker, setShowEndDatePicker] = useState(false);
  const [loading, setLoading] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const handleSubmit = async () => {
    setFormError(null);
    setSuccessMessage(null);

    if (!reason.trim()) {
      setFormError('Please provide a reason for the leave');
      return;
    }

    // Validate dates
    if (!isValid(startDate) || !isValid(endDate)) {
      setFormError('Please enter valid dates');
      return;
    }

    // Validate end date is not before start date
    if (endDate < startDate) {
      setFormError('End date cannot be before start date');
      return;
    }

    setLoading(true);
    try {
      await api.applyForLeave({
        teacherId,
        leaveType,
        reason,
        startDate: format(startDate, 'yyyy-MM-dd'),
        endDate: format(endDate, 'yyyy-MM-dd'),
      });

      setSuccessMessage('Leave application submitted successfully');
      setTimeout(() => {
        onSuccess();
        onClose();
        setReason('');
        setLeaveType('casual');
        setStartDate(new Date());
        setEndDate(new Date());
        setFormError(null);
        setSuccessMessage(null);
      }, 1500);
    } catch (error: any) {
      setFormError(error.message || 'Failed to submit leave application');
    } finally {
      setLoading(false);
    }
  };

  const onStartDateChange = (event: DateTimePickerEvent, selectedDate?: Date) => {
    if (Platform.OS === 'android') {
      setShowStartDatePicker(false);
    }
    if (selectedDate) {
      setStartDate(selectedDate);
      // Auto-update end date if it's before new start date
      if (endDate < selectedDate) {
        setEndDate(selectedDate);
      }
    }
  };

  const onEndDateChange = (event: DateTimePickerEvent, selectedDate?: Date) => {
    if (Platform.OS === 'android') {
      setShowEndDatePicker(false);
    }
    if (selectedDate) {
      // Validate end date is not before start date
      if (selectedDate < startDate) {
        setFormError('End date cannot be before start date');
        return;
      }
      setEndDate(selectedDate);
    }
  };

  return (
    <Modal visible={visible} animationType="slide">
      <View style={[styles.container, { backgroundColor: colors.background }]}>
        <View style={[styles.header, { borderBottomColor: colors.border }]}>
          <Text style={[styles.title, { color: colors.text }]}>Apply for Leave</Text>
          <TouchableOpacity onPress={onClose}>
            <Text style={[styles.closeText, { color: colors.textSecondary }]}>✕</Text>
          </TouchableOpacity>
        </View>

        <ScrollView style={styles.content}>
          {/* Inline Error/Success Messages */}
          {formError && (
            <View style={{ backgroundColor: colors.error + '15', borderRadius: 8, padding: 12, marginBottom: 16, flexDirection: 'row', alignItems: 'center' }}>
              <Ionicons name="alert-circle" size={20} color={colors.error} style={{ marginRight: 8 }} />
              <Text style={{ color: colors.error, fontSize: 14, flex: 1 }}>{formError}</Text>
            </View>
          )}
          {successMessage && (
            <View style={{ backgroundColor: colors.success + '15', borderRadius: 8, padding: 12, marginBottom: 16, flexDirection: 'row', alignItems: 'center' }}>
              <Ionicons name="checkmark-circle" size={20} color={colors.success} style={{ marginRight: 8 }} />
              <Text style={{ color: colors.success, fontSize: 14, flex: 1 }}>{successMessage}</Text>
            </View>
          )}

          <Text style={[styles.label, { color: colors.text }]}>Leave Type</Text>
          <View style={styles.leaveTypesContainer}>
            {LEAVE_TYPES.map((type) => (
              <TouchableOpacity
                key={type.value}
                style={[
                  styles.leaveTypeButton,
                  { backgroundColor: colors.inputBackground, borderColor: colors.border },
                  leaveType === type.value && { backgroundColor: colors.primary + '15', borderColor: colors.primary },
                ]}
                onPress={() => setLeaveType(type.value)}
              >
                <Text
                  style={[
                    styles.leaveTypeText,
                    { color: colors.textSecondary },
                    leaveType === type.value && { color: colors.primary, fontWeight: '600' },
                  ]}
                >
                  {type.label}
                </Text>
              </TouchableOpacity>
            ))}
          </View>

          <Text style={[styles.label, { color: colors.text }]}>Start Date</Text>
          <TouchableOpacity
            style={[styles.dateInput, { backgroundColor: colors.inputBackground, borderColor: colors.border }]}
            onPress={() => setShowStartDatePicker(true)}
          >
            <Text style={[styles.dateText, { color: colors.text }]}>
              {format(startDate, 'MMM dd, yyyy')}
            </Text>
            <Ionicons name="calendar-outline" size={20} color={colors.primary} />
          </TouchableOpacity>
          {showStartDatePicker && (
            <DateTimePicker
              value={startDate}
              mode="date"
              display={Platform.OS === 'ios' ? 'compact' : 'default'}
              onChange={onStartDateChange}
              minimumDate={new Date()}
              style={styles.datePicker}
            />
          )}

          <Text style={[styles.label, { color: colors.text }]}>End Date</Text>
          <TouchableOpacity
            style={[styles.dateInput, { backgroundColor: colors.inputBackground, borderColor: colors.border }]}
            onPress={() => setShowEndDatePicker(true)}
          >
            <Text style={[styles.dateText, { color: colors.text }]}>
              {format(endDate, 'MMM dd, yyyy')}
            </Text>
            <Ionicons name="calendar-outline" size={20} color={colors.primary} />
          </TouchableOpacity>
          {showEndDatePicker && (
            <DateTimePicker
              value={endDate}
              mode="date"
              display={Platform.OS === 'ios' ? 'compact' : 'default'}
              onChange={onEndDateChange}
              minimumDate={startDate}
              style={styles.datePicker}
            />
          )}

          <Text style={[styles.label, { color: colors.text }]}>Reason</Text>
          <TextInput
            style={[styles.input, styles.textArea, { backgroundColor: colors.inputBackground, borderColor: colors.border, color: colors.text }]}
            value={reason}
            onChangeText={setReason}
            placeholder="Enter reason for leave"
            placeholderTextColor={colors.textSecondary}
            multiline
            numberOfLines={4}
            textAlignVertical="top"
          />

          <TouchableOpacity
            style={[styles.submitButton, { backgroundColor: colors.primary }, loading && styles.submitButtonDisabled]}
            onPress={handleSubmit}
            disabled={loading}
          >
            {loading ? (
              <ActivityIndicator color={colors.white} />
            ) : (
              <Text style={[styles.submitButtonText, { color: colors.white }]}>Submit Application</Text>
            )}
          </TouchableOpacity>
        </ScrollView>
      </View>
    </Modal>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  header: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: 20,
    borderBottomWidth: 1,
  },
  title: {
    fontSize: 20,
    fontWeight: 'bold',
  },
  closeText: {
    fontSize: 28,
  },
  content: {
    flex: 1,
    padding: 20,
  },
  label: {
    fontSize: 14,
    fontWeight: '600',
    marginBottom: 8,
    marginTop: 16,
  },
  leaveTypesContainer: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: 8,
    marginBottom: 16,
  },
  leaveTypeButton: {
    paddingHorizontal: 16,
    paddingVertical: 8,
    borderRadius: 20,
    borderWidth: 1,
  },
  leaveTypeText: {
    fontSize: 14,
  },
  input: {
    borderWidth: 1,
    borderRadius: 8,
    padding: 12,
    fontSize: 16,
  },
  dateInput: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
    borderWidth: 1,
    borderRadius: 8,
    padding: 12,
    fontSize: 16,
  },
  dateText: {
    fontSize: 16,
  },
  datePicker: {
    width: '100%',
    marginTop: 8,
  },
  textArea: {
    height: 100,
  },
  submitButton: {
    padding: 16,
    borderRadius: 8,
    alignItems: 'center',
    marginTop: 24,
    marginBottom: 16,
  },
  submitButtonDisabled: {
    opacity: 0.7,
  },
  submitButtonText: {
    fontSize: 16,
    fontWeight: '600',
  },
});

